import{_ as n,c as i,o as t,a1 as r}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Plugin-Einführung: Funktionen und Risiken | Antigravity Auth","description":"Lernen Sie die Kernwerte und Risikohinweise des Antigravity Auth Plugins kennen. Zugriff auf Claude- und Gemini-3-Modelle über Google OAuth mit Unterstützung für Multi-Account-Lastausgleich.","frontmatter":{"title":"Plugin-Einführung: Funktionen und Risiken | Antigravity Auth","sidebarTitle":"Ist dieses Plugin das Richtige für Sie","subtitle":"Lernen Sie den Kernwert des Antigravity Auth Plugins kennen","description":"Lernen Sie die Kernwerte und Risikohinweise des Antigravity Auth Plugins kennen. Zugriff auf Claude- und Gemini-3-Modelle über Google OAuth mit Unterstützung für Multi-Account-Lastausgleich.","tags":["Einstieg","Plugin-Einführung","OpenCode","Antigravity"],"order":1},"headers":[],"relativePath":"de/NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md","filePath":"de/NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md"}'),a={name:"de/NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md"};function s(l,e,o,u,h,d){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="lernen-sie-den-kernwert-des-antigravity-auth-plugins-kennen" tabindex="-1">Lernen Sie den Kernwert des Antigravity Auth Plugins kennen <a class="header-anchor" href="#lernen-sie-den-kernwert-des-antigravity-auth-plugins-kennen" aria-label="Permalink to &quot;Lernen Sie den Kernwert des Antigravity Auth Plugins kennen&quot;">​</a></h1><p><strong>Antigravity Auth</strong> ist ein OpenCode-Plugin, das über Google OAuth-Authentifizierung auf die Antigravity API zugreift. Es ermöglicht Ihnen den Aufruf fortschrittlicher KI-Modelle wie Claude Opus 4.5, Sonnet 4.5 und Gemini 3 Pro/Flash mit Ihrem gewohnten Google-Konto – ohne API-Schlüssel verwalten zu müssen. Das Plugin bietet auch Multi-Account-Lastausgleich, duale Kontingent-Pools und automatische Sitzungswiederherstellung. Es ist ideal für Benutzer, die fortschrittliche Modelle und automatisierte Verwaltung benötigen.</p><h2 id="was-sie-nach-diesem-kurs-erreichen-konnen" tabindex="-1">Was Sie nach diesem Kurs erreichen können <a class="header-anchor" href="#was-sie-nach-diesem-kurs-erreichen-konnen" aria-label="Permalink to &quot;Was Sie nach diesem Kurs erreichen können&quot;">​</a></h2><ul><li>Einschätzen, ob dieses Plugin zu Ihrem Anwendungsfall passt</li><li>Verstehen, welche KI-Modelle und Kernfunktionen das Plugin unterstützt</li><li>Die Risiken und Vorsichtsmaßnahmen beim Einsatz dieses Plugins kennen</li><li>Entscheiden, ob Sie mit Installation und Konfiguration fortfahren möchten</li></ul><h2 id="ihre-aktuelle-herausforderung" tabindex="-1">Ihre aktuelle Herausforderung <a class="header-anchor" href="#ihre-aktuelle-herausforderung" aria-label="Permalink to &quot;Ihre aktuelle Herausforderung&quot;">​</a></h2><p>Sie möchten auf die fortschrittlichsten KI-Modelle zugreifen (wie Claude Opus 4.5, Gemini 3 Pro), haben aber eingeschränkten offiziellen Zugriff. Sie suchen nach einer zuverlässigen Möglichkeit, diese Modelle zu nutzen, und möchten:</p><ul><li>Keine mehreren API-Schlüssel manuell verwalten müssen</li><li>Bei Ratenbegrenzungen automatisch auf andere Konten umschalten</li><li>Nach Unterbrechungen automatisch die Konversation fortsetzen, ohne Kontext zu verlieren</li></ul><h2 id="die-kernidee" tabindex="-1">Die Kernidee <a class="header-anchor" href="#die-kernidee" aria-label="Permalink to &quot;Die Kernidee&quot;">​</a></h2><p><strong>Antigravity Auth</strong> ist ein OpenCode-Plugin, das über <strong>Google OAuth-Authentifizierung</strong> auf die Google Antigravity API zugreift und Ihnen ermöglicht, fortschrittliche KI-Modelle mit Ihrem gewohnten Google-Konto aufzurufen.</p><p>Es fungiert nicht als Proxy für alle Anfragen, sondern <strong>interzeptiert und konvertiert</strong> Ihre Modellaufrufe, leitet sie an die Antigravity API weiter und konvertiert die Antworten zurück in ein von OpenCode verständliches Format.</p><h2 id="hauptfunktionen" tabindex="-1">Hauptfunktionen <a class="header-anchor" href="#hauptfunktionen" aria-label="Permalink to &quot;Hauptfunktionen&quot;">​</a></h2><h3 id="unterstutzte-modelle" tabindex="-1">Unterstützte Modelle <a class="header-anchor" href="#unterstutzte-modelle" aria-label="Permalink to &quot;Unterstützte Modelle&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Modellreihe</th><th>Verfügbare Modelle</th><th>Besonderheiten</th></tr></thead><tbody><tr><td><strong>Claude</strong></td><td>Opus 4.5, Sonnet 4.5</td><td>Unterstützt erweiterten Denkmodus</td></tr><tr><td><strong>Gemini 3</strong></td><td>Pro, Flash</td><td>Google Search-Integration, erweitertes Denken</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Denkmodus (Thinking)</p><p>Thinking-Modelle führen vor der Antwortgenerierung eine &quot;Tiefenanalyse&quot; durch und zeigen den Schlussfolgerungsprozess an. Sie können das Denkbudget konfigurieren, um Qualität und Antwortgeschwindigkeit abzuwägen.</p></div><h3 id="multi-account-lastausgleich" tabindex="-1">Multi-Account-Lastausgleich <a class="header-anchor" href="#multi-account-lastausgleich" aria-label="Permalink to &quot;Multi-Account-Lastausgleich&quot;">​</a></h3><ul><li><strong>Unterstützung für bis zu 10 Google-Konten</strong></li><li>Automatischer Wechsel zum nächsten Konto bei Ratenbegrenzung (429-Fehler)</li><li>Drei Kontoauswahlstrategien: sticky (fest), round-robin (rotation), hybrid (intelligente Mischung)</li></ul><h3 id="duales-kontingentsystem" tabindex="-1">Duales Kontingentsystem <a class="header-anchor" href="#duales-kontingentsystem" aria-label="Permalink to &quot;Duales Kontingentsystem&quot;">​</a></h3><p>Das Plugin greift gleichzeitig auf <strong>zwei unabhängige Kontingent-Pools</strong> zu:</p><ol><li><strong>Antigravity-Kontingent</strong>: Aus der Google Antigravity API</li><li><strong>Gemini CLI-Kontingent</strong>: Aus dem Google Gemini CLI</li></ol><p>Wenn ein Pool ratenbegrenzt wird, versucht das Plugin automatisch den anderen Pool zu nutzen, um die Kontingentnutzung zu maximieren.</p><h3 id="automatische-sitzungswiederherstellung" tabindex="-1">Automatische Sitzungswiederherstellung <a class="header-anchor" href="#automatische-sitzungswiederherstellung" aria-label="Permalink to &quot;Automatische Sitzungswiederherstellung&quot;">​</a></h3><ul><li>Erkennt fehlgeschlagene Tool-Aufrufe (z.B. Unterbrechung durch ESC-Taste)</li><li>Injiziert automatisch synthetic tool_result, um Konversationsabstürze zu verhindern</li><li>Unterstützt automatisches Senden von &quot;continue&quot; zur Fortsetzung der Konversation</li></ul><h3 id="google-search-integration" tabindex="-1">Google Search-Integration <a class="header-anchor" href="#google-search-integration" aria-label="Permalink to &quot;Google Search-Integration&quot;">​</a></h3><p>Aktiviert Websuche für Gemini-Modelle, um die Faktengenauigkeit zu verbessern:</p><ul><li><strong>Auto-Modus</strong>: Das Modell entscheidet basierend auf Bedarf, ob gesucht werden soll</li><li><strong>Always-on-Modus</strong>: Bei jeder Anfrage wird gesucht</li></ul><h2 id="wann-sollten-sie-dieses-plugin-verwenden" tabindex="-1">Wann sollten Sie dieses Plugin verwenden <a class="header-anchor" href="#wann-sollten-sie-dieses-plugin-verwenden" aria-label="Permalink to &quot;Wann sollten Sie dieses Plugin verwenden&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Geeignet für folgende Szenarien</p><ul><li>Sie haben mehrere Google-Konten und möchten die Gesamtkontingente erhöhen</li><li>Sie müssen Thinking-Modelle von Claude oder Gemini 3 nutzen</li><li>Sie möchten Google Search für Gemini-Modelle aktivieren</li><li>Sie möchten keine API-Schlüssel manuell verwalten, sondern bevorzugen OAuth-Authentifizierung</li><li>Sie stoßen häufig auf Ratenbegrenzungen und möchten automatisch zwischen Konten wechseln</li></ul></div><div class="warning custom-block"><p class="custom-block-title">Nicht geeignet für folgende Szenarien</p><ul><li>Sie müssen Modelle verwenden, die Google offiziell nicht veröffentlicht hat</li><li>Sie sind sehr sensibel gegenüber Google ToS-Risiken (siehe Risikohinweis unten)</li><li>Sie benötigen nur grundlegende Gemini 1.5- oder Claude 3-Modelle (offizielle Schnittstellen sind stabiler)</li><li>Sie haben Schwierigkeiten, den Browser in WSL-, Docker- oder ähnlichen Umgebungen zu öffnen</li></ul></div><h2 id="⚠️-wichtiger-risikohinweis" tabindex="-1">⚠️ Wichtiger Risikohinweis <a class="header-anchor" href="#⚠️-wichtiger-risikohinweis" aria-label="Permalink to &quot;⚠️ Wichtiger Risikohinweis&quot;">​</a></h2><p>Die Nutzung dieses Plugins <strong>kann gegen die Nutzungsbedingungen von Google verstoßen</strong>. Einige wenige Benutzer haben berichtet, dass ihre Google-Konten <strong>gesperrt</strong> oder <strong>schatten-gesperrt</strong> (Zugriff eingeschränkt, aber keine explizite Benachrichtigung) wurden.</p><h3 id="hochrisiko-szenarien" tabindex="-1">Hochrisiko-Szenarien <a class="header-anchor" href="#hochrisiko-szenarien" aria-label="Permalink to &quot;Hochrisiko-Szenarien&quot;">​</a></h3><ul><li>🚨 <strong>Brandneue Google-Konten</strong>: Sehr hohe Wahrscheinlichkeit einer Sperrung</li><li>🚨 <strong>Konten mit neu abgeschlossenem Pro/Ultra-Abonnement</strong>: Leicht als verdächtig markiert und gesperrt</li></ul><h3 id="bitte-bestatigen-sie-vor-der-nutzung" tabindex="-1">Bitte bestätigen Sie vor der Nutzung <a class="header-anchor" href="#bitte-bestatigen-sie-vor-der-nutzung" aria-label="Permalink to &quot;Bitte bestätigen Sie vor der Nutzung&quot;">​</a></h3><ul><li>Dies ist ein <strong>inoffizielles Tool</strong>, das von Google nicht anerkannt wird</li><li>Ihr Konto kann ausgesetzt oder dauerhaft gesperrt werden</li><li>Sie tragen das volle Risiko bei der Nutzung dieses Plugins</li></ul><h3 id="empfehlungen" tabindex="-1">Empfehlungen <a class="header-anchor" href="#empfehlungen" aria-label="Permalink to &quot;Empfehlungen&quot;">​</a></h3><ul><li>Verwenden Sie <strong>etablierte Google-Konten</strong>, anstatt neue Konten speziell für dieses Plugin zu erstellen</li><li>Vermeiden Sie die Nutzung wichtiger Konten, die an kritische Dienste gebunden sind</li><li>Falls Ihr Konto gesperrt wird, können Sie über dieses Plugin keinen Einspruch einlegen</li></ul><div class="danger custom-block"><p class="custom-block-title">Kontosicherheit</p><p>Alle OAuth-Token werden lokal in <code>~/.config/opencode/antigravity-accounts.json</code> gespeichert und auf keine Server hochgeladen. Bitte stellen Sie jedoch sicher, dass Ihr Computer sicher ist, um Token-Lecks zu verhindern.</p></div><h2 id="zusammenfassung-dieser-lektion" tabindex="-1">Zusammenfassung dieser Lektion <a class="header-anchor" href="#zusammenfassung-dieser-lektion" aria-label="Permalink to &quot;Zusammenfassung dieser Lektion&quot;">​</a></h2><p>Antigravity Auth ist ein leistungsstarkes OpenCode-Plugin, das Ihnen über Google OAuth Zugriff auf Claude- und Gemini 3-Hochleistungsmodelle ermöglicht. Es bietet Multi-Account-Lastausgleich, duale Kontingent-Pools, automatische Sitzungswiederherstellung und andere Funktionen. Es ist ideal für Benutzer, die Hochleistungsmodelle und automatisierte Verwaltung benötigen.</p><p>Bitte beachten Sie jedoch: <strong>Die Nutzung dieses Plugins birgt das Risiko einer Kontosperrung</strong>. Bitte verwenden Sie nicht kritische Google-Konten und informieren Sie sich über die damit verbundenen Risiken, bevor Sie mit der Installation fortfahren.</p><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir <strong><a href="./../../quick-install/">Schnellinstallation</a></strong>.</p><p>Sie werden lernen:</p><ul><li>Plugin-Installation in 5 Minuten</li><li>Hinzufügen des ersten Google-Kontos</li><li>Überprüfung der erfolgreichen Installation</li></ul></blockquote>',42)])])}const f=n(a,[["render",s]]);export{c as __pageData,f as default};
